    "clean_ocr_text": "",
    "key_entities": [
      "Узел 2",
      "Стальная труба 30х15х2 мм",
      "Окраска в цвет металла Sunsong SNJS-22100",
      "30",
      "15",
      "Sunsong SNJS-22100"
    ]
  }
}

{
